ValidationRule.errorConditionFormula:
AND(
    NOT(ISBLANK(RFC__c)),
    OR(
        AND(
            ISPICKVAL(tipos_de_contribuyentes__c, "Persona Física"),
            NOT(
                REGEX(
                    RFC__c,
                    "^[A-ZÑ&]{4}[0-9]{2}(0[1-9]|1[0-2])(0[1-9]|[12][0-9]|3[01])[A-Z0-9]{3}$"
                )
            )
        ),
        AND(
            ISPICKVAL(tipos_de_contribuyentes__c, "Persona Moral"),
            NOT(
                REGEX(
                    RFC__c,
                    "^[A-ZÑ&]{3}[0-9]{2}(0[1-9]|1[0-2])(0[1-9]|[12][0-9]|3[01])[A-Z0-9]{3}$"
                )
            )
        )
    )
)
